import data from "../data/logement.json";
import { Link } from "react-router-dom";

const Home = () => {
  return (
    <>
    <div className="toto">
      {data.map((item, index) => {
        return (
          <Link to={`/logement/${item.id}`}>

            <Card key={index} />
          </Link>
        );
      })}
    </div>
    </>
  );
};

export default Home;
